def convert(s: str, numRows: int) -> str:
    if numRows == 1:
        return s

    rows = [""] * numRows
    current_row = 0
    going_down = False  # Başlangıçta yönü yukarı olarak varsay, ilk karakterde aşağı dönecek

    for char in s:
        rows[current_row] += char

        # Eğer en üst veya en alt sıradaysak yönü değiştir
        if current_row == 0 or current_row == numRows - 1:
            going_down = not going_down

        # Yeni sıraya geç
        if going_down:
            current_row += 1
        else:
            current_row -= 1

    return "".join(rows)
